#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        char S[100005]; scanf("%s", S);
        int ans = N; // default when no other '1'
        for(int i=1;i<N;i++){
            if(S[i]=='1'){ ans = i; break; }
        }
        printf("%d\n", ans);
    }
    return 0;
}

